"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useStore } from "@/lib/store/useStore";
import styles from "./Login.module.css";
import { Phone, Lock, ArrowRight, UserPlus } from "lucide-react";
import Link from "next/link";

export default function LoginPage() {
  const [phone, setPhone] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { login, checkSession, isAuthenticated } = useStore();
  const router = useRouter();

  useEffect(() => {
    checkSession();
  }, [checkSession]);

  useEffect(() => {
    if (isAuthenticated) {
      router.push('/');
    }
  }, [isAuthenticated, router]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError("");

    const success = await login(phone, password);
    if (success) {
      router.push('/');
    } else {
      setError("Invalid phone number or PIN. Please try again.");
      setIsSubmitting(false);
    }
  };

  return (
    <div className={styles.container}>
      <div className={styles.loginCard}>
        <header className={styles.header}>
          <div className={styles.dot} />
          <h1>WELCOME BACK</h1>
          <p>Login to your Kirana OS account</p>
        </header>

        <form onSubmit={handleLogin} className={styles.form}>
          <div className={styles.inputGroup}>
            <label><Phone size={14} /> Phone Number</label>
            <input 
              type="text" 
              placeholder="Enter your registered phone"
              value={phone}
              onChange={(e) => setPhone(e.target.value)}
              required
            />
          </div>

          <div className={styles.inputGroup}>
            <label><Lock size={14} /> Secret PIN / Password</label>
            <input 
              type="password" 
              placeholder="Enter your PIN"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          {error && <div className={styles.error}>{error}</div>}

          <button type="submit" className={styles.loginBtn} disabled={isSubmitting}>
            {isSubmitting ? "Authenticating..." : "Login to Dashboard"}
            {!isSubmitting && <ArrowRight size={18} />}
          </button>
        </form>

        <footer className={styles.footer}>
          <span>New to Kirana OS?</span>
          <Link href="/register" className={styles.registerLink}>
            <UserPlus size={14} /> Create New Account
          </Link>
        </footer>
      </div>
      
      <div className={styles.bgOrb} />
    </div>
  );
}
